# compute LCS function
def lcs_length(a,b):
    # compute length of longest common subsequence (not substring)
    # but maybe we want longest common substring? They suggested LCS or token F1.
    # We'll compute longest common subsequence with dynamic programming.
    la, lb = len(a), len(b)
    # convert to lists of chars
    A, B = a, b
    # Use DP table
    dp = [[0]*(lb+1) for _ in range(la+1)]
    for i in range(la-1, -1, -1):
        for j in range(lb-1, -1, -1):
            if A[i]==B[j]:
                dp[i][j] = 1 + dp[i+1][j+1]
            else:
                dp[i][j] = max(dp[i+1][j], dp[i][j+1])
    return dp[0][0]

# token overlap F1
import math
def token_f1(a,b):
    # tokenize by whitespace
    atoks = a.split()
    btoks = b.split()
    if not atoks or not btoks:
        return 0.0
    atok_counts = {}
    for t in atoks:
        atok_counts[t] = atok_counts.get(t,0)+1
    common = 0
    for t in btoks:
        if atok_counts.get(t,0)>0:
            common += 1
            atok_counts[t] -= 1
    prec = common/len(btoks)
    rec = common/len(atoks)
    if prec+rec==0:
        return 0.0
    return 2*prec*rec/(prec+rec)

